const generateDungeonMonsters = (floorIndex) => {
    const floorData = DUNGEON_FLOORS[floorIndex] || DUNGEON_FLOORS[0];
    return floorData.monsters.map((m, i) => {
        let newMonster = { ...INITIAL_STATS, ...JSON.parse(JSON.stringify(m)), id: `dungeon_mob_${floorIndex}_${i}`, isPlayer: false, isCompanion: false };
        newMonster.hp = newMonster.baseHp;
        newMonster.maxhp = newMonster.baseHp;
        newMonster.atk = newMonster.baseAtk;
        newMonster.def = newMonster.baseDef;
        newMonster.spd = newMonster.baseSpd;
        newMonster.equippedSkills = { combat_basic_1: null, combat_basic_2: null, combat_ultimate: null, adventure_1: null, adventure_2: null, adventure_3: null };
        if (newMonster.skills && Array.isArray(newMonster.skills)) {
            newMonster.skills.forEach((s, idx) => {
                s.currentCooldown = 0;
                if (s.skillCategory === 'ultimate') newMonster.equippedSkills.combat_ultimate = s;
                else if (!newMonster.equippedSkills.combat_basic_1) newMonster.equippedSkills.combat_basic_1 = s;
                else newMonster.equippedSkills.combat_basic_2 = s;
            });
            delete newMonster.skills;
        }
        return newMonster;
    });
};

