const getFinalRarityByILvl = (iLvl, itemType = 'default') => {
    let levelRange;
    if (iLvl <= 20) levelRange = '1-20';
    else if (iLvl <= 40) levelRange = '21-40';
    else if (iLvl <= 60) levelRange = '41-60';
    else if (iLvl <= 80) levelRange = '61-80';
    else levelRange = '81-100';

    let finalDistribution = { ...RARITY_DISTRIBUTION_BY_ILVL[levelRange] };
    
    if (itemType === 'Tạp vật') {
        return 'Thường';
    } else if (itemType === 'Nguyên liệu' || itemType === 'Tín vật') {
        finalDistribution['Cực Phẩm'] = 0;
        finalDistribution['Siêu Phẩm'] = 0;
        finalDistribution['Huyền Thoại'] = 0;
        finalDistribution['Thường'] += 10;
        finalDistribution['Tốt'] += 5;
    }
    
    const rand = Math.random() * 100;
    let cumulative = 0;
    for (const rarity in finalDistribution) {
        cumulative += finalDistribution[rarity];
        if (rand < cumulative) return rarity;
    }
    return 'Thường';
};

// HÀM TÍNH TOÁN CẤP ĐỘ (iLvl) VÀ NGÂN SÁCH (PV) MỚI
const calculateItemPower = (referenceLevel, forcedType = 'default', forcedRarity = null, forcedLevel = null) => {
    let iLvl = forcedLevel !== null 
        ? forcedLevel 
        : (referenceLevel + Math.floor(Math.random() * 16) - 5);
    iLvl = Math.max(1, Math.min(100, iLvl));
    const rarity = forcedRarity || getFinalRarityByILvl(iLvl, forcedType);
    const basePV = 10 + ((iLvl - 1) * (4990 / 99));
    const rarityMultiplier = RARITY_MULTIPLIERS_PV[rarity] || 1.0;
    
    let totalPV = Math.floor(basePV * rarityMultiplier);
    
    if (canHaveEffects(forcedType, rarity, totalPV)) {
        totalPV = Math.floor(totalPV * 1.15);
    }
    
    return { iLvl, rarity, totalPV };
};
const calculateItemValue = (totalPV, category) => {
    const typeMultiplier = TYPE_MULTIPLIERS_VALUE[category] || 1.0;
    return Math.floor(totalPV * typeMultiplier);
};

const generateStaticDungeonLoot = (category, rarity, floor, playerLevel, assignedUid = null) => {
    const safeLevel = playerLevel || 30; // Chống lỗi mất cấp độ
    const powerData = calculateItemPower(safeLevel, category, rarity, safeLevel);
    const finalValue = calculateItemValue(powerData.totalPV, category);
    
    let stats = "";
    let effectsStr = "";
    let durationHours = undefined;

    // Phân rã thuộc tính chống lỗi
    if (category === 'Vũ khí') stats = `atk:${Math.max(5, Math.floor(powerData.totalPV / 10))}`;
    else if (['Đầu', 'Thân', 'Chân', 'Phụ kiện'].includes(category)) stats = `def:${Math.max(5, Math.floor(powerData.totalPV / 10))}`;
    else if (category === 'Trữ vật') stats = `carry_weight:${Math.max(10, Math.floor(powerData.totalPV / 20))}`;
    else if (category === 'Đan dược') effectsStr = `HEAL:target=self,formula=MAX_HP*0.25`;
    else if (category === 'Thực phẩm') {
        effectsStr = `APPLY_DYNAMIC_STATUS:target=all_allies,name=No Bụng,type=food_buff,duration=4,stat_changes=HP_PERCENT:10`;
        durationHours = 4;
    }
    else if (category === 'Đa năng') effectsStr = `DAMAGE:target=single_enemy,formula=FIXED:${Math.max(50, powerData.totalPV)},true_damage=false`;

    const item = {
        id: crypto.randomUUID(),
        Name: `Chiến lợi phẩm Tầng ${floor} (${category})`,
        description: "Vật chất ngưng tụ rớt ra trong hầm ngục.",
        Type: category,
        Rarity: rarity,
        Weight: 1.0,
        Value: finalValue,
        Stats: stats,
        effectsString: effectsStr,
        effectDurationInHours: durationHours,
        quantity: 1, 
        Consumable: ['Đan dược', 'Đa năng', 'Thực phẩm'].includes(category),
        Equippable: ['Vũ khí', 'Thân', 'Đầu', 'Chân', 'Phụ kiện', 'Trữ vật', 'Phương tiện', 'Dị thường'].includes(category),
        Requirements: `level:${powerData.iLvl}`
    };

    if (assignedUid) {
        item.assignedToUid = assignedUid;
    }

    return item;
};

const canHaveEffects = (category, rarity, totalPV = 0) => {
    if (category === 'Trữ vật') return false;
    if (category === 'Dị thường') return true;
    const hasSufficientBudget = totalPV >= 1000;
    const isHighRarity = ['Hiếm', 'Cực Phẩm', 'Siêu Phẩm', 'Huyền Thoại'].includes(rarity);   
    return isHighRarity && hasSufficientBudget;
};

const getAllocationRules = (hasEffects, iLvl = 1) => {
    // Đoạn chỉ thị động ép AI chọn đúng loại chỉ số theo giai đoạn game
    let statGuidanceInstruction = "";
    if (iLvl <= 25) {
        statGuidanceInstruction = `
// >>> CHỈ THỊ CHỌN CHỈ SỐ GIAI ĐOẠN ĐẦU (Cấp trang bị hiện tại: Cấp ${iLvl} - THẤP) <<<
// Vì trang bị này có cấp độ thấp (Level 1-25), các chỉ số tăng theo phần trăm (%) sẽ vô dụng vì chỉ số gốc của người chơi lúc này rất nhỏ.
// - Ngươi BẮT BUỘC phải ưu tiên tuyệt đối các chỉ số CỘNG THẲNG (Flat): "atk", "def", "spd", "hp".
// - Hạn chế tối đa hoặc KHÔNG dùng các chỉ số phần trăm như "atk_percent", "atk_amp", "cr"... (Ngoại trừ Dị thường).
`;
    } else {
        statGuidanceInstruction = `
// >>> CHỈ THỊ CHỌN CHỈ SỐ GIAI ĐOẠN MUỘN (Cấp trang bị hiện tại: Cấp ${iLvl} - CAO) <<<
// Trang bị này có cấp độ cao (Level 30-100), lúc này chỉ số gốc của người chơi đã rất lớn.
// - Ngươi BẮT BUỘC phải ưu tiên các chỉ số PHẦN TRĂM (%) và KHUẾCH ĐẠI: "atk_percent", "def_percent", "spd_percent", "hp_percent", "cr", "cdmg", "atk_amp", "dmg_amp", "dmg_res", "evasion".
// - Hạn chế dùng các chỉ số cộng thẳng (Flat) như "atk", "def" vì chúng sẽ bị loãng ở giai đoạn này.
`;
    }

    return `
// --- BỘ LUẬT PHÂN BỔ NGÂN SÁCH CHIẾN ĐẤU (BẮT BUỘC) ---
// TƯỚC QUYỀN SỐ HỌC: Ngươi TUYỆT ĐỐI KHÔNG CẦN xuất ra "Stats", "Requirements" hay "Value". Máy chủ sẽ tự tính.
// Ngươi CHỈ ĐƯỢC PHÉP xuất ra TỶ LỆ PHẦN TRĂM (%) phân bổ sức mạnh vào thuộc tính "StatAllocation". Ngươi có 100% tài nguyên để chia.

${hasEffects ? `
// 1. Ngân sách Hiệu ứng: Dành một phần ngân sách (từ 10% đến 50% tùy độ bá đạo) cho hiệu ứng cơ chế ('effects'). Không khai báo số này, chỉ cần ngầm hiểu phần dư ra là của hiệu ứng.
// 2. Ngân sách Chỉ số ('StatAllocation'): Tổng các con số trong 'StatAllocation' + phần trăm của hiệu ứng = 100.
// Ví dụ: Ngươi định cho hiệu ứng chiếm 30% ngân sách. Vậy 'StatAllocation' chỉ được tổng cộng 70 (Ví dụ: {"atk": 40, "cr": 30}).
` : `
// 1. Ngân sách Chỉ số ('StatAllocation'): Món đồ này KHÔNG có hiệu ứng. Ngươi PHẢI chia đủ 100% ngân sách vào các chỉ số trong 'StatAllocation'.
// Ví dụ: {"atk": 70, "hp": 30}. (Tổng bằng 100).
`}

${statGuidanceInstruction}

// BẢNG PHÂN BIỆT ĐỊNH DẠNG KEY ĐỂ ĐIỀN VÀO 'StatAllocation':
// - Nhóm Cộng Thẳng (Flat - Số nguyên): "atk", "def", "spd", "hp".
// - Nhóm Phần Trăm (%): "atk_percent", "def_percent", "spd_percent", "hp_percent", "cr", "cdmg", "atk_amp", "def_amp", "spd_amp", "hp_amp", "dmg_amp", "dmg_res", "evasion".
`;
};

