// Helper Functions
const AvatarDisplay = React.memo(({ 
    entity, 
    handleUserUploadAvatar, 
    onAutoGenerate, 
    isPlayerAvatar = false, 
    className = "w-20 h-20", 
    shapeClass = "rounded-md", 
    readOnly = false,
    isGenerating = false
}) => {
    const [localAvatarSrc, setLocalAvatarSrc] = useState(null);
    const [isLoadingAvatar, setIsLoadingAvatar] = useState(true);
    const [inputUrl, setInputUrl] = useState('');
    const [isEditingUrl, setIsEditingUrl] = useState(false);
    const [isZoomed, setIsZoomed] = useState(false);
    const fileInputRef = useRef(null);
    
    useEffect(() => {
        let isMounted = true;
        const fetchAvatar = async () => {
            setIsLoadingAvatar(true);
            if (entity.avatarStoredLocally && entity.id) {
                const base64 = await getAvatarFromIndexedDB(entity.id);
                if (isMounted && base64) {
                    setLocalAvatarSrc(base64);
                    setIsLoadingAvatar(false);
                    return;
                }
            }
            if (isMounted && entity.avatarBase64) {
                const src = entity.avatarBase64.startsWith('data:image') ? entity.avatarBase64 : `data:image/jpeg;base64,${entity.avatarBase64}`;
                setLocalAvatarSrc(src);
            } else if (isMounted && entity.avatarUrl && entity.avatarUrl.trim() !== '') {
                setLocalAvatarSrc(entity.avatarUrl);
            } else if (isMounted && entity.images && (entity.images.idle || entity.images.base)) {
                setLocalAvatarSrc(entity.images.idle || entity.images.base);
            }
            setIsLoadingAvatar(false);
        };
        fetchAvatar();
        return () => { isMounted = false; };
    }, [entity.id, entity.avatarStoredLocally, entity.avatarUrl, entity.avatarBase64, entity.lastAvatarUpdate, entity.images?.base, entity.images?.idle]);
    
    const handleFileUpload = (e) => {
        const file = e.target.files[0];
        if (!file) return;
        const reader = new FileReader();
        reader.onloadend = () => {
            if (handleUserUploadAvatar) handleUserUploadAvatar(isPlayerAvatar ? reader.result : entity.id, reader.result);
            setIsEditingUrl(false);
        };
        reader.readAsDataURL(file);
    };

    const displaySrc = localAvatarSrc || "https://placehold.co/80x80/162216/cda45e?text=??";

    return (
        <>
            <div className={`${className} relative group flex-shrink-0`}> 
                <div 
                    className={`w-full h-full ${shapeClass} object-cover border border-[#cda45e]/40 flex items-center justify-center bg-[#0a0f0a] overflow-hidden ${!isGenerating ? 'cursor-pointer hover:border-[#cda45e] hover:brightness-110' : 'cursor-wait opacity-80'} transition-all duration-300`}
                    onClick={(e) => { 
                        if (isGenerating) return;
                        e.preventDefault(); e.stopPropagation(); setIsZoomed(true); 
                    }}
                >
                    {isLoadingAvatar || isGenerating ? (
                        <div className="w-1/2 h-1/2 border-2 border-t-transparent border-[#cda45e] rounded-full animate-spin"></div>
                    ) : (
                        <img
                            src={displaySrc}
                            alt={entity.Name}
                            className="w-full h-full object-cover transition-transform duration-300 group-hover:scale-105"
                            onError={(e) => { e.target.src="https://placehold.co/80x80/162216/cda45e?text=Lỗi"; }}
                        />
                    )}
                </div>

                {!readOnly && !isGenerating && (
                    <>
                        <input type="file" accept="image/*" ref={fileInputRef} onChange={handleFileUpload} className="hidden" />
                        <button
                            onClick={(e) => { e.stopPropagation(); fileInputRef.current?.click(); }}
                            className="absolute -top-2 -left-2 bg-gray-800 border border-gray-500 rounded-full p-1 text-green-400 hover:text-white hover:bg-green-600 shadow-md z-10 opacity-0 group-hover:opacity-100 transition-opacity"
                            title="Tải ảnh từ máy"
                        >
                            <PhotoIcon className="w-3 h-3" />
                        </button>
                        <button
                            onClick={(e) => { e.stopPropagation(); setIsEditingUrl(true); }}
                            className="absolute -top-2 -right-2 bg-gray-800 border border-gray-500 rounded-full p-1 text-gray-300 hover:text-white hover:bg-purple-600 shadow-md z-10 opacity-0 group-hover:opacity-100 transition-opacity"
                            title="Nhập URL ảnh"
                        >
                            <PencilIcon className="w-3 h-3" />
                        </button>
                        <button
                            onClick={(e) => { e.stopPropagation(); onAutoGenerate && onAutoGenerate(entity); }}
                            className="absolute -bottom-2 -right-2 bg-gray-800 border border-gray-500 rounded-full p-1 text-yellow-400 hover:text-white hover:bg-yellow-600 shadow-md z-10 opacity-0 group-hover:opacity-100 transition-opacity"
                            title="AI Vẽ Chân Dung"
                        >
                            <SparklesIcon className="w-3 h-3" />
                        </button>
                    </>
                )}

                {isEditingUrl && !isGenerating && (
                    <div className="absolute top-0 left-0 w-64 bg-gray-900 border border-purple-600 rounded-lg shadow-xl p-3 z-50 translate-x-10">
                        <p className="text-xs text-gray-300 mb-2">Nhập URL ảnh:</p>
                        <input
                            type="url"
                            value={inputUrl}
                            onChange={(e) => setInputUrl(e.target.value)}
                            className="w-full text-xs p-2 bg-gray-800 border border-gray-700 rounded-md text-white mb-2"
                            autoFocus
                            onClick={(e) => e.stopPropagation()}
                        />
                        <div className="flex justify-end gap-2">
                            <button onClick={(e) => {
                                e.stopPropagation();
                                if(inputUrl) handleUserUploadAvatar(isPlayerAvatar ? reader.result : entity.id, reader.result);
                                setIsEditingUrl(false);
                                setInputUrl('');
                            }} className="bg-purple-600 text-white text-xs px-2 py-1 rounded">Lưu</button>
                            <button onClick={(e) => { e.stopPropagation(); setIsEditingUrl(false); }} className="bg-gray-600 text-white text-xs px-2 py-1 rounded">Hủy</button>
                        </div>
                    </div>
                )}
            </div>

            {isZoomed && (
                <div 
                    className="fixed inset-0 z-[9999] bg-black/90 backdrop-blur-sm flex items-center justify-center p-4 cursor-zoom-out animate-fade-in"
                    onClick={(e) => { e.stopPropagation(); setIsZoomed(false); }}
                >
                    <img src={displaySrc} alt="Phóng to" className="max-w-full max-h-[90vh] object-contain drop-shadow-[0_0_50px_rgba(205,164,94,0.3)] border border-[#cda45e]/50 rounded-sm" />
                    <div className="absolute bottom-10 left-1/2 -translate-x-1/2 text-gray-400 text-sm font-bold tracking-widest uppercase bg-black/60 px-6 py-2 rounded-full pointer-events-none">
                        Nhấn vào để đóng
                    </div>
                </div>
            )}
        </>
    );
});

