const MessageModal = ({ show, title, content, type, onClose }) => {
    if (!show) return null;
    let titleColor = 'text-[#e8d3a1]';
    let borderColor = 'border-[#cda45e]/50';
    let IconComponent = () => <InformationCircleIcon className="w-7 h-7 mr-3 text-[#cda45e]"/>;
    
    if (type === 'error') {
        titleColor = 'text-[#ff4d4d]';
        borderColor = 'border-[#8b1515]';
        IconComponent = () => <ExclamationTriangleIcon className="w-7 h-7 mr-3 text-[#ff4d4d]"/>;
    } else if (type === 'success') {
        titleColor = 'text-[#8ba888]';
        borderColor = 'border-[#8ba888]';
        IconComponent = () => <CheckIcon className="w-7 h-7 mr-3 text-[#8ba888]"/>;
    }

    // Bảo vệ React không bị crash nếu content vô tình là một Object (ví dụ: error object)
    const safeContent = typeof content === 'object' && content !== null 
        ? (content.message || JSON.stringify(content)) 
        : String(content || '');

    const safeTitle = typeof title === 'object' && title !== null 
        ? JSON.stringify(title) 
        : String(title || '');

    return (
      <div className="fixed inset-0 bg-[#0a0f0a]/80 backdrop-blur-sm flex items-center justify-center p-4 z-[500]"> 
        <div className={`bg-[#162216] p-8 shadow-[0_0_40px_rgba(10,20,10,0.9)] w-full max-w-md border ${borderColor} relative`}>
            {/* Góc kim loại */}
            <div className={`absolute top-0 left-0 w-4 h-4 border-t-2 border-l-2 ${borderColor.replace('border-', 'border-t-').replace('border-', 'border-l-')} pointer-events-none`}></div>
            <div className={`absolute top-0 right-0 w-4 h-4 border-t-2 border-r-2 ${borderColor.replace('border-', 'border-t-').replace('border-', 'border-r-')} pointer-events-none`}></div>
            <div className={`absolute bottom-0 left-0 w-4 h-4 border-b-2 border-l-2 ${borderColor.replace('border-', 'border-b-').replace('border-', 'border-l-')} pointer-events-none`}></div>
            <div className={`absolute bottom-0 right-0 w-4 h-4 border-b-2 border-r-2 ${borderColor.replace('border-', 'border-b-').replace('border-', 'border-r-')} pointer-events-none`}></div>

          <div className="flex items-center mb-5 border-b border-[#a3b8a3]/20 pb-3">
            <IconComponent />
            <h3 className={`text-2xl font-bold tracking-widest ${titleColor}`} style={{ fontFamily: "'Noto Serif Vietnamese', serif" }}>{safeTitle}</h3>
          </div>
          <p className="text-[#a3b8a3] mb-8 whitespace-pre-line leading-relaxed break-words">{safeContent}</p>
          <button
            onClick={onClose}
            className="w-full bg-transparent border border-[#cda45e] hover:bg-[#cda45e]/10 text-[#cda45e] font-bold py-3 uppercase tracking-widest text-sm transition-all"
          >
            Tuân Mệnh
          </button>
        </div>
      </div>
    );
};

