                <button onClick={onClose} className="absolute top-2 right-3 sm:top-4 sm:right-5 text-[#a3b8a3] hover:text-[#e8d3a1] text-3xl sm:text-4xl font-bold leading-none transition-colors z-[60]">×</button>

