const buildAvatarPrompt = (character, gameSettings) => {
    let genderStr = "androgynous style with neutral fantasy features";
    
    // Sửa lỗi nhận diện giới tính chặt chẽ hơn
    const rawGender = (character.Gender || character.characterGender || "").toLowerCase().trim();
    if (rawGender === "nam" || rawGender.includes("đàn ông") || rawGender.includes("nam giới")) {
        genderStr = "handsome male with distinct masculine features";
    } else if (rawGender === "nữ" || rawGender.includes("phụ nữ") || rawGender.includes("nữ giới") || rawGender.includes("cái")) {
        genderStr = "beautiful female with distinct feminine features, gorgeous";
    }

    const role = character.Role ? `Role and Profession: ${character.Role}. ` : "Adventurer. ";
    const personality = character.Personality || "neutral";
    
    let rawAppearance = (character.Appearance || character.description || "").trim();
    if (rawAppearance.length < 10) {
        const theme = gameSettings?.theme || "fantasy";
        rawAppearance = `A striking character suited for a ${theme} world, wearing traditional travel clothes matching their profession, gazing forward.`;
    }

    const theme = gameSettings?.theme || "Fantasy";
    
    // Bổ sung tên nhân vật để AI nhận diện IP (cực kỳ quan trọng với chế độ Đồng Nhân)
    const charName = character.Name ? `Character Name: ${character.Name} (If this is a famous fictional character from novels/anime/manga, try to draw them accurately based on your training data). ` : "";

    return `
        A stunning 2D anime manga character portrait (head, face and upper chest only) for a video game avatar. 
        ${charName}
        Setting/Theme/Genre: ${theme}. 
        Gender and Appearance Type: ${genderStr}.
        ${role}Personality: ${personality}.
        Appearance Details (Please translate to English and follow exactly): ${rawAppearance.substring(0, 300)}.
        
        CRITICAL INSTRUCTIONS: 
        - 2D flat illustration, hand-drawn game art style. NO 3D RENDER. NO PHOTOREALISM.
        - Include a matching, aesthetic, slightly blurred fantasy background.
        - No text, no watermarks, no interface elements.
        - Strictly follow the theme and the provided description.
    `.trim();
};

const generateSingleImage = async (promptText, effectiveApiKey) => {
    console.log("Đang gọi API Gemini 3.1 Flash cho NHÂN VẬT với prompt:", promptText); 
    
    const apiUrl = `https://generativelanguage.googleapis.com/v1beta/models/gemini-3.1-flash-image:generateContent?key=${effectiveApiKey}`;
    const payload = {
        contents: [{ role: "user", parts: [{ text: `Generate an image: ${promptText}` }] }],
        generationConfig: { responseModalities: ["IMAGE"] }
    };
    
    // BỌC VÀO HÀNG CHỜ ĐỂ TRÁNH LỖI 429
    const executeImageFetch = async () => {
        const response = await fetch(apiUrl, { 
            method: 'POST', 
            headers: { 'Content-Type': 'application/json' }, 
            body: JSON.stringify(payload) 
        });
        
        if (!response.ok) {
            const errText = await response.text();
            console.error("Lỗi API Gemini 3.1 (Nhân Vật):", errText);
            throw new Error(errText || `API trả về lỗi HTTP ${response.status}`);
        }
        
        const result = await response.json();
        const base64 = result.candidates?.[0]?.content?.parts?.find(p => p.inlineData)?.inlineData?.data;
        
        if (!base64) throw new Error("Không có dữ liệu ảnh trả về từ AI.");
        
        console.log("Tạo Ảnh Nhân Vật THÀNH CÔNG!");
        return `data:image/jpeg;base64,${base64}`;
    };

    return globalApiQueue.enqueue(executeImageFetch);
};

