                                                    className="px-2 py-0.5 bg-[#8b1515]/20 border border-[#ff4d4d]/60 hover:bg-[#8b1515] text-[#ff4d4d] hover:text-white text-[9px] font-bold uppercase rounded-sm transition-colors"
