                                            <p className="text-[10px] text-[#8ba888] mb-3 italic">Trạng thái: {activeImageUrl ? "Đã nạp" : "Trống"}. Dán link ảnh mới để gán dáng.</p>
                                            <input 
                                                type="text" 
                                                placeholder="Dán URL đè lên..." 
