const parseStoryWithDialogue = (text) => {
    if (!text || typeof text !== 'string') return [];

    const segments = [];
    let lastIndex = 0;
    // Regex tìm thẻ <dialogue>
    const regex = /<dialogue speaker="([^"]+)">([\s\S]*?)<\/dialogue>/g;
    let match;

    while ((match = regex.exec(text)) !== null) {
        // 1. Lấy phần văn kể chuyện đứng TRƯỚC thẻ dialogue
        if (match.index > lastIndex) {
            const narrativeContent = text.substring(lastIndex, match.index).trim();
            if (narrativeContent) {
                segments.push({
                    type: 'narrative',
                    content: narrativeContent
                });
            }
        }

        // 2. Lấy thông tin từ thẻ dialogue
        segments.push({
            type: 'dialogue',
            speaker: match[1].trim(),
            content: match[2].trim()
        });

        lastIndex = regex.lastIndex;
    }

    // 3. Lấy phần văn kể chuyện còn lại SAU thẻ dialogue cuối cùng
    if (lastIndex < text.length) {
        const remainingContent = text.substring(lastIndex).trim();
        if (remainingContent) {
            segments.push({
                type: 'narrative',
                content: remainingContent
            });
        }
    }

    // Nếu không tìm thấy thẻ dialogue nào, trả về toàn bộ text là narrative
    if (segments.length === 0 && text.trim()) {
        segments.push({ type: 'narrative', content: text.trim() });
    }

    return segments;
};

const FirebaseConfigModal = ({ 
    show, 
    onClose, 
    onConnectSuccess, 
    cloudVipKey, 
    setCloudVipKey, 
    setIsValidatedVip, 
    setVipOwnerName, 
    setShowVipWelcomeModal 
}) => {
    const [activeTab, setActiveTab] = React.useState("vip");
    const [configText, setConfigText] = React.useState("");
    const [vipInput, setVipInput] = React.useState("");
    const [error, setError] = React.useState("");
    const [isLoading, setIsLoading] = React.useState(false);

    React.useEffect(() => {
        if (show) {
            setError("");
            setConfigText("");
            setVipInput(cloudVipKey || "");
            setIsLoading(false);
            setActiveTab(cloudVipKey ? "vip" : "vip");
        }
    }, [show, cloudVipKey]);

    if (!show) return null;

    const handleManualConnect = () => {
        setError("");
        if (!configText.trim()) {
            setError("Vui lòng dán cấu hình Firebase vào ô trống.");
            return;
        }

        const result = initializeDynamicFirebase(configText);
        if (result.success) {
            setConfigText("");
            onConnectSuccess();
        } else {
            setError(result.error || "Cấu hình không hợp lệ. Vui lòng copy đúng đoạn firebaseConfig.");
        }
    };

    const handleVipConnect = async () => {
        setError("");
        const cleanKey = vipInput.trim();
        if (!cleanKey) {
            setError("Vui lòng nhập Mã Khóa VIP.");
            return;
        }

        setIsLoading(false);
        setIsLoading(true);
        try {
            const check = await verifyVipKeyInCloud(cleanKey);
            if (!check || !check.isValid) {
                throw new Error("Mã Khóa VIP không hợp lệ hoặc đã hết hạn.");
            }

            const response = await fetch(`${SUPABASE_URL}/rest/v1/system_config?config_name=eq.pvp_firebase_config&select=config_value`, {
                method: 'GET',
                headers: {
                    'apikey': SUPABASE_ANON_KEY,
                    'Authorization': `Bearer ${SUPABASE_ANON_KEY}`
                }
            });

            if (!response.ok) {
                throw new Error("Không thể tải cấu hình máy chủ từ cơ sở dữ liệu đám mây.");
            }

            const data = await response.json();
            if (!data || data.length === 0) {
                throw new Error("Không tìm thấy cấu hình máy chủ kết nối chung.");
            }

            const pvpConfigStr = data[0].config_value;
            const initResult = initializeDynamicFirebase(pvpConfigStr);
            if (initResult.success) {
                if (setCloudVipKey) setCloudVipKey(check.keyCode.trim());
                if (setIsValidatedVip) setIsValidatedVip(true);
                if (setVipOwnerName) setVipOwnerName(check.ownerName || 'Ký Chủ');
                
                onConnectSuccess();
            } else {
                throw new Error(initResult.error || "Khởi tạo kết nối máy chủ lôi đài thất bại.");
            }

        } catch (err) {
            setError(err.message || "Đã xảy ra lỗi không xác định.");
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="fixed inset-0 bg-[#0a0f0a]/90 backdrop-blur-sm z-[300] flex items-center justify-center p-4 animate-fade-in">
            <div className="bg-[#162216] w-full max-w-lg border border-[#cda45e]/50 flex flex-col relative shadow-[0_0_30px_rgba(10,20,10,0.9)] p-6">
                
                <div className="absolute top-0 left-0 w-4 h-4 border-t-2 border-l-2 border-[#cda45e] pointer-events-none"></div>
                <div className="absolute top-0 right-0 w-4 h-4 border-t-2 border-r-2 border-[#cda45e] pointer-events-none"></div>
                <div className="absolute bottom-0 left-0 w-4 h-4 border-b-2 border-l-2 border-[#cda45e] pointer-events-none"></div>
                <div className="absolute bottom-0 right-0 w-4 h-4 border-b-2 border-r-2 border-[#cda45e] pointer-events-none"></div>

                <div className="flex justify-between items-center mb-4 border-b border-[#cda45e]/30 pb-2">
                    <h3 className="text-xl font-bold text-[#cda45e] tracking-widest" style={{ fontFamily: "'Noto Serif Vietnamese', serif" }}>
                        KẾT NỐI MÁY CHỦ
                    </h3>
                    <button onClick={onClose} disabled={isLoading} className="text-[#a3b8a3] hover:text-[#ff4d4d] text-2xl font-bold leading-none disabled:opacity-50">&times;</button>
                </div>

                <div className="flex bg-[#0a0f0a] border border-[#cda45e]/30 p-0.5 mb-5 rounded-sm flex-shrink-0">
                    <button 
                        onClick={() => { if(!isLoading) { setActiveTab("vip"); setError(""); } }} 
                        className={`flex-1 py-2 text-xs font-bold tracking-widest uppercase transition-colors rounded-sm ${activeTab === 'vip' ? 'bg-[#cda45e]/20 text-[#e8d3a1] border border-[#cda45e]/40' : 'text-[#8ba888] hover:text-[#cda45e]'}`}
                    >
                        Cổng VIP Tự Động
                    </button>
                    <button 
                        onClick={() => { if(!isLoading) { setActiveTab("manual"); setError(""); } }} 
                        className={`flex-1 py-2 text-xs font-bold tracking-widest uppercase transition-colors rounded-sm ${activeTab === 'manual' ? 'bg-[#cda45e]/20 text-[#e8d3a1] border border-[#cda45e]/40' : 'text-[#8ba888] hover:text-[#cda45e]'}`}
                    >
                        Cấu Hình Thủ Công
                    </button>
                </div>

                {activeTab === 'vip' ? (
                    <div className="space-y-4 animate-fade-in">
                        <p className="text-[#8ba888] text-xs leading-relaxed">
                            Nhập Mã Khóa VIP của ngươi để tự động trích xuất thông số và khởi chạy kết nối lôi đài chung:
                        </p>
                        <input
                            type="password"
                            value={vipInput}
                            onChange={(e) => setVipInput(e.target.value.toUpperCase())}
                            disabled={isLoading}
                            placeholder="NHẬP MÃ KHÓA VIP..."
                            className="w-full p-3 text-center font-mono tracking-widest bg-[#0a0f0a] border border-[#cda45e]/40 text-[#e8d3a1] focus:border-[#cda45e] outline-none text-sm disabled:opacity-50"
                        />
                    </div>
                ) : (
                    <div className="space-y-4 animate-fade-in">
                        <p className="text-[#8ba888] text-xs leading-relaxed">
                            Dán nguyên đoạn mã cấu hình chứa <span className="text-[#e8d3a1] font-mono bg-[#101a10] px-1 py-0.5 rounded">firebaseConfig = {"{ ... }"}</span> vào đây:
                        </p>
                        <textarea
                            value={configText}
                            onChange={(e) => setConfigText(e.target.value)}
                            disabled={isLoading}
                            placeholder='const firebaseConfig = {&#10;  apiKey: "...",&#10;  authDomain: "...",&#10;  ...&#10;};'
                            className="w-full h-40 bg-[#0a0f0a] border border-[#cda45e]/30 text-[#e8d3a1] p-3 text-sm font-mono focus:outline-none focus:border-[#cda45e] scrollbar-thin scrollbar-thumb-[#cda45e] disabled:opacity-50"
                        />
                    </div>
                )}

                {error && <p className="text-[#ff4d4d] text-sm mt-4 animate-pulse font-bold">{error}</p>}

                <div className="flex justify-end gap-3 mt-6 border-t border-[#cda45e]/20 pt-4">
                    <button onClick={onClose} disabled={isLoading} className="px-6 py-2.5 border border-[#8ba888]/60 text-[#8ba888] hover:bg-[#8ba888]/10 transition-colors font-bold text-xs tracking-wider disabled:opacity-50">
                        HỦY BỎ
                    </button>
                    {activeTab === 'vip' ? (
                        <button 
                            onClick={handleVipConnect} 
                            disabled={isLoading}
                            className="px-6 py-2.5 bg-[#1b2a1b] border border-[#cda45e] text-[#e8d3a1] hover:bg-[#cda45e] hover:text-[#0a0f0a] transition-all font-bold text-xs tracking-wider shadow-[0_0_15px_rgba(205,164,94,0.2)] flex items-center justify-center gap-2 disabled:opacity-50"
                        >
                            {isLoading ? (
                                <>
                                    <div className="w-3.5 h-3.5 border-2 border-t-transparent border-[#0a0f0a] rounded-full animate-spin"></div>
                                    <span>ĐANG KẾT NỐI...</span>
                                </>
                            ) : "KẾT NỐI SIÊU TỐC"}
                        </button>
                    ) : (
                        <button 
                            onClick={handleManualConnect} 
                            disabled={isLoading}
                            className="px-6 py-2.5 bg-[#1b2a1b] border border-[#cda45e] text-[#e8d3a1] hover:bg-[#cda45e] hover:text-[#0a0f0a] transition-all font-bold text-xs tracking-wider"
                        >
                            KẾT NỐI
                        </button>
                    )}
                </div>
            </div>
        </div>
    );
};
