const registerCriticalPromise = (promise) => {
    const timeoutPromise = new Promise((resolve) => {
        setTimeout(() => {
            resolve({ timeout: true });
        }, 10000);
    });

    const wrappedPromise = Promise.race([promise, timeoutPromise]).catch((err) => {
        console.error("Critical promise failed:", err);
        return { error: true };
    });

    activeCriticalPromisesRef.current.push(wrappedPromise);

    const cleanup = () => {
        activeCriticalPromisesRef.current = activeCriticalPromisesRef.current.filter(p => p !== wrappedPromise);
    };

    wrappedPromise.then(cleanup).catch(cleanup);
    return wrappedPromise;
};
