const handleSaveToSupabaseCloud = async (slotNumber) => {
    setIsProcessingAction(true);
    setModalMessage({ 
        show: true, 
        title: "Đang Đồng Bộ Đám Mây", 
        content: "Bắt đầu trích xuất dữ liệu từ Thức Hải...", 
        type: "info" 
    });

    // Nhường luồng cho UI vẽ popup
    await new Promise(resolve => setTimeout(resolve, 50));

    try {
        const knowledgeCopy = JSON.parse(JSON.stringify(knowledge));
        const player = knowledgeCopy.characters.find(c => c.isPlayer);

        let totalImagesToUpload = 0;
        let uploadedImages = 0;

        setModalMessage({ 
            show: true, 
            title: "Đồng Bộ Đám Mây", 
            content: "Đang kiểm tra và chuẩn bị đưa hình ảnh lên mây...", 
            type: "info" 
        });
        await new Promise(resolve => setTimeout(resolve, 50));

        const htabChar = knowledgeCopy.characters.find(c => c.id === 'system_assistant');
        if (htabChar) {
            const localHtabImages = { ...(htabChar.images || {}) };

            const expressions = ['base', 'idle', 'smile', 'sad', 'angry', 'laugh', 'avatar', 'love', 'wow', 'smug', 'bashful', 'pout', 'exhausted', 'evil', 'speechless', 'sleepy', 'scared'];
            for (const expr of expressions) {
                const cachedExpr = await getAvatarFromIndexedDB(`system_assistant_${expr}`);
                if (cachedExpr) {
                    localHtabImages[expr] = cachedExpr;
                }
            }

            const cachedHtabImages = await getAvatarFromIndexedDB('system_assistant_images');
            if (cachedHtabImages) {
                for (const expr in cachedHtabImages) {
                    if (!localHtabImages[expr]) {
                        localHtabImages[expr] = cachedHtabImages[expr];
                    }
                }
            }

            // Đếm số lượng ảnh cần tải lên của HTAB
            for (const expr in localHtabImages) {
                if (localHtabImages[expr] && typeof localHtabImages[expr] === 'string' && localHtabImages[expr].startsWith('data:image')) {
                    totalImagesToUpload++;
                }
            }

            // Tải ảnh HTAB lên ImgBB
            for (const expr in localHtabImages) {
                if (localHtabImages[expr] && typeof localHtabImages[expr] === 'string' && localHtabImages[expr].startsWith('data:image')) {
                    try {
                        localHtabImages[expr] = await uploadImageToImgBB(localHtabImages[expr]);
                        uploadedImages++;
                        setModalMessage({ show: true, title: "Đang Tải Ảnh", content: `Đang tải ảnh Hệ Thống lên mây (${uploadedImages})...`, type: "info" });
                    } catch (e) {
                        console.warn(`Lỗi đồng bộ biểu cảm ${expr} của Hệ Thống lên ImgBB:`, e);
                    }
                }
            }

            htabChar.images = localHtabImages;
            
            if (knowledgeCopy.systemAssistant) {
                knowledgeCopy.systemAssistant.images = localHtabImages;
            }

            const cachedHtabAvatar = await getAvatarFromIndexedDB('system_assistant');
            const currentAvatar = cachedHtabAvatar || localHtabImages.avatar || htabChar.avatarUrl;
            if (currentAvatar && typeof currentAvatar === 'string' && currentAvatar.startsWith('data:image')) {
                try {
                    const cloudUrl = await uploadImageToImgBB(currentAvatar);
                    htabChar.avatarUrl = cloudUrl;
                    htabChar.avatarBase64 = null;
                    if (knowledgeCopy.htab) {
                        knowledgeCopy.htab.avatarBase64 = cloudUrl;
                    }
                    uploadedImages++;
                    setModalMessage({ show: true, title: "Đang Tải Ảnh", content: `Đang tải Avatar Hệ Thống lên mây...`, type: "info" });
                } catch (e) {
                    console.warn("Lỗi đồng bộ chân dung Hệ Thống lên ImgBB:", e);
                }
            } else if (currentAvatar && typeof currentAvatar === 'string') {
                htabChar.avatarUrl = currentAvatar;
                htabChar.avatarBase64 = null;
                if (knowledgeCopy.htab) {
                    knowledgeCopy.htab.avatarBase64 = currentAvatar;
                }
            }
        }

        // Xử lý ảnh nhân vật khác
        for (const char of knowledgeCopy.characters) {
            if (char && char.id !== 'system_assistant' && !char.isPermanentlyDead) {
                const isPl = char.isPlayer || char.id === 'player' || char.id === 'player_fallback';
                const charId = isPl ? 'player' : char.id;

                const cachedAvatar = await getAvatarFromIndexedDB(charId);
                if (cachedAvatar && typeof cachedAvatar === 'string' && cachedAvatar.startsWith('data:image')) {
                    try {
                        setModalMessage({ show: true, title: "Đang Tải Ảnh", content: `Đang tải Avatar của ${char.Name}...`, type: "info" });
                        const cloudUrl = await uploadImageToImgBB(cachedAvatar);
                        char.avatarBase64 = null; 
                        char.avatarUrl = cloudUrl; 
                        uploadedImages++;
                    } catch (e) {
                        console.warn(`Lỗi đồng bộ avatar nhân vật ${char.Name}:`, e);
                    }
                }

                const cleanId = currentGameId ? currentGameId.replace(/^(autosave_|manual_\d+_)/, '') : '';
                const cachedImages = await getAvatarFromIndexedDB(`${cleanId}_${charId}_images`);
                if (cachedImages) {
                    const cloudImages = { ...cachedImages };
                    for (const typeKey in cloudImages) {
                        if (typeKey === 'skills' && typeof cloudImages.skills === 'object') {
                            const cloudSkills = { ...cloudImages.skills };
                            for (const sId in cloudSkills) {
                                if (cloudSkills[sId] && typeof cloudSkills[sId] === 'string' && cloudSkills[sId].startsWith('data:image')) {
                                    try {
                                        setModalMessage({ show: true, title: "Đang Tải Ảnh", content: `Đang tải ảnh Kỹ năng của ${char.Name}...`, type: "info" });
                                        cloudSkills[sId] = await uploadImageToImgBB(cloudSkills[sId]);
                                        uploadedImages++;
                                    } catch (e) {
                                        console.warn(`Lỗi đồng bộ kỹ năng ${sId} của ${char.Name}:`, e);
                                    }
                                }
                            }
                            cloudImages.skills = cloudSkills;
                        } else if (cloudImages[typeKey] && typeof cloudImages[typeKey] === 'string' && cloudImages[typeKey].startsWith('data:image')) {
                            try {
                                setModalMessage({ show: true, title: "Đang Tải Ảnh", content: `Đang tải ảnh Dáng (${typeKey}) của ${char.Name}...`, type: "info" });
                                cloudImages[typeKey] = await uploadImageToImgBB(cloudImages[typeKey]);
                                uploadedImages++;
                            } catch (e) {
                                console.warn(`Lỗi đồng bộ dáng ${typeKey} của ${char.Name}:`, e);
                            }
                        }
                    }
                    char.images = cloudImages;
                }
            }
        }

        // Dọn dẹp rác Base64 cục bộ để file nhẹ đi
        knowledgeCopy.characters.forEach(char => {
            if (!char) return;
            char.avatarBase64 = null; 
            if (char.images) {
                const cleanImages = { ...char.images };
                for (const key in cleanImages) {
                    if (key === 'skills') continue;
                    if (cleanImages[key] && typeof cleanImages[key] === 'string' && cleanImages[key].startsWith('data:image')) {
                        cleanImages[key] = null;
                    }
                }
                if (cleanImages.skills && typeof cleanImages.skills === 'object') {
                    const cleanSkills = { ...cleanImages.skills };
                    for (const sId in cleanSkills) {
                        if (cleanSkills[sId] && typeof cleanSkills[sId] === 'string' && cleanSkills[sId].startsWith('data:image')) {
                            cleanSkills[sId] = null;
                        }
                    }
                    cleanImages.skills = cleanSkills;
                }
                char.images = cleanImages;
            }
        });

        if (knowledgeCopy.htab && knowledgeCopy.htab.avatarBase64 && typeof knowledgeCopy.htab.avatarBase64 === 'string' && knowledgeCopy.htab.avatarBase64.startsWith('data:image')) {
            knowledgeCopy.htab.avatarBase64 = null;
        }
        if (knowledgeCopy.systemAssistant && knowledgeCopy.systemAssistant.images) {
            const cleanSysImages = { ...knowledgeCopy.systemAssistant.images };
            for (const key in cleanSysImages) {
                if (cleanSysImages[key] && typeof cleanSysImages[key] === 'string' && cleanSysImages[key].startsWith('data:image')) {
                    cleanSysImages[key] = null;
                }
            }
            knowledgeCopy.systemAssistant.images = cleanSysImages;
        }

        const activePlayerAvatar = await getAvatarFromIndexedDB('player');
        const avatarThumbnail = activePlayerAvatar ? await compressToThumbnail(activePlayerAvatar) : null;
        const cleanStoryHistoryForCloud = storyHistory.map(item => {
            if (item.knowledgeSnapshot) {
                const { knowledgeSnapshot, ...rest } = item;
                return rest;
            }
            return item;
        });

        const saveData = {
            currentTurn: currentTurn,
            saveVersion: "3.0_supabase_cloud",
            timestamp: new Date().toISOString(),
            gameSettings: {
                ...gameSettings,
                playerAvatarThumbnail: avatarThumbnail
            },
            knowledge: knowledgeCopy,
            storyHistory: cleanStoryHistoryForCloud, 
            choices: choices,
            gameMode: gameMode,
            storySummaries: storySummaries,
            adventureTurnCount: adventureTurnCount,
        };

        const metadata = {
            gameSettings: {
                characterName: gameSettings.characterName,
                storyTitle: gameSettings.storyTitle,
                difficulty: gameSettings.difficulty,
                playerAvatarThumbnail: avatarThumbnail
            },
            currentTurn: currentTurn
        };

        // --- BƯỚC NÉN DỮ LIỆU GÂY ĐƠ TAB ĐƯỢC CÁCH LY ---
        setModalMessage({ 
            show: true, 
            title: "Nén Dữ Liệu", 
            content: "Đang nén hàng ngàn dòng lịch sử vào ngọc phiến (Sẽ hơi lag một chút, vui lòng không tắt trình duyệt)...", 
            type: "info" 
        });
        
        // Buộc trình duyệt phải vẽ dòng chữ cảnh báo lag ra màn hình TRƯỚC KHI CPU bị khóa chết
        await new Promise(resolve => setTimeout(resolve, 100));

        const jsonString = JSON.stringify(saveData);
        // Thuật toán này khóa CPU:
        const compressed = window.LZString.compressToUTF16(jsonString);

        // Nén xong, nhường luồng một chút trước khi gọi mạng
        await new Promise(resolve => setTimeout(resolve, 50));
        
        setModalMessage({ 
            show: true, 
            title: "Tải Lên Mây", 
            content: "Nén hoàn tất. Đang bắn dữ liệu lên máy chủ hệ thống...", 
            type: "info" 
        });

        await saveGameToCloudDb(cloudVipKey, slotNumber, compressed, metadata);

        const newSaveObj = {
            id: `manual_${slotNumber}_supabase`,
            isSupabaseCloud: true,
            ...saveData,
            updatedAt: { toDate: () => new Date() }
        };

        setSavedGames(prev => {
            const filtered = prev.filter(g => g.id !== `manual_${slotNumber}_supabase`);
            const merged = [newSaveObj, ...filtered];
            merged.sort((a, b) => {
                const timeA = a.updatedAt?.toDate ? a.updatedAt.toDate().getTime() : 0;
                const timeB = b.updatedAt?.toDate ? b.updatedAt.toDate().getTime() : 0;
                return timeB - timeA;
            });
            return merged;
        });

        setModalMessage({ 
            show: true, 
            title: "Đồng Bộ Thành Công", 
            content: `Ngọc phiến số ${slotNumber} đã được ghi nhớ vĩnh viễn trên đám mây!`, 
            type: "success" 
        });

    } catch (err) {
        setModalMessage({ show: true, title: "Lưu Thất Bại", content: err.message, type: "error" });
    } finally {
        setIsProcessingAction(false);
    }
};

const handleAppraiseNpc = async (npcId) => {
    const npc = knowledge.characters.find(c => c.id === npcId);
    if (!npc) return;

    setIsProcessingAction(true);
    setModalMessage({ show: true, title: 'Đang Giám Định...', content: `Đấng đang sử dụng Thiên Nhãn để nhìn thấu thân phận, quá khứ và tính cách của [${npc.Name}]...`, type: 'info' });

    try {
        const effectiveApiKey = apiMode === 'userKey' ? apiKey : "";
        if (apiMode === 'userKey' && !effectiveApiKey) throw new Error("API Key chưa được cấu hình.");

        const playerLvl = playerCharacter?.level || 1;
        const detailedNpcProfile = await fetchNpcDetailsFromAI(npc, gameSettings, effectiveApiKey, playerLvl);

        if (!detailedNpcProfile) throw new Error("AI không thể trích xuất thông tin NPC.");

        setknowledge(prev => {
            const newKnowledge = JSON.parse(JSON.stringify(prev));
            const charIndex = newKnowledge.characters.findIndex(c => c.id === npcId);
            
            if (charIndex > -1) {
                let charToUpdate = newKnowledge.characters[charIndex];
                // Cập nhật các trường mới
                charToUpdate.Role = detailedNpcProfile.Role;
                charToUpdate.Appearance = detailedNpcProfile.Appearance;
                charToUpdate.Backstory = detailedNpcProfile.Backstory;
                charToUpdate.Personality = detailedNpcProfile.Personality;
                charToUpdate.Stance = detailedNpcProfile.Stance;
                
                // Xử lý cập nhật level và tính toán lại Base Stats nếu Level thay đổi
                if (detailedNpcProfile.level !== charToUpdate.level) {
                    charToUpdate.level = detailedNpcProfile.level;
                    charToUpdate.baseHp = 200 + (charToUpdate.level - 1) * 20;
                    charToUpdate.baseAtk = 20 + (charToUpdate.level - 1) * 2;
                    charToUpdate.baseDef = 10 + (charToUpdate.level - 1) * 1;
                    charToUpdate.baseSpd = 30 + (charToUpdate.level - 1) * 1;
                    // Auto cộng AP cho NPC
                    charToUpdate.ap = calculateTotalAP(charToUpdate.level);
                    charToUpdate = autoAllocateNpcAp(charToUpdate);
                }

                // Xóa trường description chung chung đi để thay bằng Appearance + Backstory
                charToUpdate.description = ""; 
                charToUpdate.isAppraised = true; // Đánh dấu là đã được giám định
                
                // Cập nhật lại chỉ số cuối
                newKnowledge.characters[charIndex] = calculateFinalStats(charToUpdate);
            }
            return newKnowledge;
        });

        setModalMessage({ show: true, title: 'Giám Định Hoàn Tất', content: `Đã nhìn thấu toàn bộ thông tin của [${npc.Name}]! Hãy xem trong bảng chi tiết.`, type: 'success' });

        } catch (error) {
            console.error("Lỗi khi giám định NPC:", error);
            setModalMessage({ show: true, title: 'Giám Định Thất Bại', content: `Không thể nhìn thấu mục tiêu: ${error.message}`, type: 'error' });
        } finally {
            setIsProcessingAction(false);
        }
    };
    

    const handleGenerateVfxImage = async (prompt) => {
        const effectiveApiKey = apiMode === 'userKey' ? apiKey : "";
        if (apiMode === 'userKey' && !effectiveApiKey) {
            setModalMessage({ show: true, title: 'Lỗi API Key', content: 'Vui lòng cấu hình API Key để sử dụng tính năng này.', type: 'error' });
            throw new Error("Chưa cấu hình API Key");
        }
        return await generateSingleImage(prompt, effectiveApiKey);
    };

const handleDebugUpdateCharacter = (characterId, updates) => {
    setknowledge(prevKnowledge => {
        const newKnowledge = JSON.parse(JSON.stringify(prevKnowledge));
        const charIndex = newKnowledge.characters.findIndex(c => c.id === characterId);

        if (charIndex === -1) {
            console.error("Lỗi: Không tìm thấy nhân vật với ID:", characterId);
            return prevKnowledge;
        }

        let characterToUpdate = newKnowledge.characters[charIndex];

        for (const key in updates) {
            characterToUpdate[key] = updates[key];
        }

        newKnowledge.characters[charIndex] = calculateFinalStats(characterToUpdate, newKnowledge.characters);
        return newKnowledge;
    });
};

const handleStartSandboxCombat = () => {
    setBackupChoices(choices);
    setBackupCustomActionInput(customActionInput);
    preCombatSnapshotRef.current = JSON.parse(JSON.stringify(knowledge.characters));

    withCurtainTransition(async () => {
        const partyRaw = knowledge.characters.filter(c => (c.isPlayer || c.isCompanion) && c.inParty !== false);
        const partyToProcess = partyRaw.length > 0 ? JSON.parse(JSON.stringify(partyRaw)) : [{
            ...INITIAL_STATS,
            id: 'player',
            isPlayer: true,
            Name: gameSettings.characterName || 'Hành Giả',
        }];

        const refreshedPlayerParty = partyToProcess.map(char => {
            char.combatStatuses = [];
            char.longTermStatuses = (char.longTermStatuses || []).filter(s => {
                const sType = (s.type || s.status_type || "").toLowerCase();
                return !sType.includes("debuff") && !sType.includes("injury");
            });

            if (char.equippedSkills) {
                for (let k in char.equippedSkills) {
                    if (char.equippedSkills[k]) {
                        char.equippedSkills[k].currentCooldown = 0;
                        if (char.equippedSkills[k].effects) {
                            char.equippedSkills[k].effects.forEach(e => {
                                if (e.action) {
                                    e.action.currentCooldown = 0;
                                }
                            });
                        }
                    }
                }
            }
            if (char.skills) {
                char.skills.forEach(s => {
                    if (s) {
                        s.currentCooldown = 0;
                        if (s.effects) {
                            s.effects.forEach(e => {
                                if (e.action) {
                                    e.action.currentCooldown = 0;
                                }
                            });
                        }
                    }
                });
            }
            if (char.learnedSkills) {
                char.learnedSkills.forEach(s => {
                    if (s) {
                        s.currentCooldown = 0;
                    }
                });
            }

            const calculated = calculateFinalStats(char, knowledge.characters);
            calculated.hp = calculated.maxhp;
            return calculated;
        });

        const sandboxBg = 'https://i.postimg.cc/c4KH1L0f/San-Dau-Tap-Tho-So-San-loi-dai-(Arena).jpg';
        const dummyImage = 'https://i.postimg.cc/NfVKRrdq/Hinh-Nhan-The-Than-Ky-nang-(VFX).png';

        setCombatEnvironmentImage(sandboxBg);

        const hostPlayer = refreshedPlayerParty.find(p => p.isPlayer) || refreshedPlayerParty[0];
        const targetDummies = [1, 2, 3, 4].map(num => ({
            id: `dummy_${num}`,
            Name: `Hình Nhân ${num}`,
            Role: "Bia Thử Lực",
            description: "Hình nhân thế thân chịu đòn.",
            level: hostPlayer.level || 1,
            Gender: "Không xác định",
            Stance: "Thù địch",
            Personality: "Thụ động",
            sizeCategory: 2,
            baseHp: 99999, baseAtk: 0, baseDef: 10, baseSpd: 1, 
            hp: 99999, maxhp: 99999, atk: 0, def: 10, spd: 1,
            cr: 0, cdmg: 150, evasion: 0, dmgRes: 0, dmgAmp: 0,
            skills: [],
            images: { base: dummyImage, idle: dummyImage, attack_normal: dummyImage, skills: {} }
        }));
        
        const refreshedEnemies = targetDummies.map(e => calculateFinalStats(e));

        const imagesToPreload = [sandboxBg, dummyImage];
        refreshedPlayerParty.forEach(char => {
            if (char.images) {
                if (char.images.base) imagesToPreload.push(char.images.base);
                if (char.images.idle) imagesToPreload.push(char.images.idle);
                if (char.images.attack_normal) imagesToPreload.push(char.images.attack_normal);

                if (char.images.skills) {
                    Object.values(char.images.skills).forEach(skillImgUrl => {
                        if (skillImgUrl) imagesToPreload.push(skillImgUrl);
                    });
                }
            } else if (char.avatarBase64) {
                imagesToPreload.push(char.avatarBase64);
            } else if (char.avatarUrl) {
                imagesToPreload.push(char.avatarUrl);
            }

            const allSkills = [...(char.skills || []), ...Object.values(char.equippedSkills || {}).filter(Boolean)];
            allSkills.forEach(skill => {
                const rootVfx = skill.visual_effects?.customImageUrl;
                const actionVfx = skill.effects?.[0]?.action?.visual_effects?.customImageUrl;
                if (rootVfx) imagesToPreload.push(rootVfx);
                if (actionVfx) imagesToPreload.push(actionVfx);
            });
            if (char.basicAttackVfx?.customImageUrl) imagesToPreload.push(char.basicAttackVfx.customImageUrl);
        });

        const uniqueImagesToPreload = Array.from(new Set(imagesToPreload.filter(Boolean)));

        await Promise.all(uniqueImagesToPreload.map(url => {
            return new Promise((resolve) => {
                const img = new Image();
                img.src = url;
                img.onload = () => resolve();
                img.onerror = () => resolve();
            });
        }));

        setModalMessage({ show: false, title: "", content: "", type: "info" });
        setIsLoading(false);
        setIsProcessingAction(false);
        
        setCombatInitializationData({
            playerParty: refreshedPlayerParty,
            enemies: refreshedEnemies,
            combatType: 'Sandbox'
        });

        setGameMode('COMBAT');
        setChoices([]);
        
        setCombatLog([{
            id: crypto.randomUUID(),
            round: 0,
            actor: "Hệ thống",
            skill: "",
            target: "",
            message: "--- BẮT ĐẦU ĐẤU TẬP THỬ NGHIỆM --- \nHình nhân thế thân đã được thiết lập. Hãy thỏa sức thử nghiệm chiêu thức!"
        }]);
    });
};


const loadGameAndResetHistory = async (gameData) => {
    if (!gameData) {
        setModalMessage({ show: true, title: 'Lỗi', content: 'Dữ liệu game không hợp lệ.', type: 'error' });
        return;
    }
    try {
        setCurrentScreen('loading');
        performStateCleanup();

        let finalGameData = { ...gameData };

        if (gameData.isSupabaseCloud && !gameData.knowledge) {
            setModalMessage({ show: true, title: "Đang Tải Đám Mây", content: "Đang tải dữ liệu cốt truyện chi tiết từ máy chủ Vip...", type: "info" });
            try {
                const compressedData = await fetchFullSaveFromCloud(gameData.supabaseRowId);
                const decompressedStr = window.LZString.decompressFromUTF16(compressedData) || atob(compressedData);
                const parsedFullData = JSON.parse(decompressedStr);
                finalGameData = { ...finalGameData, ...parsedFullData };
            } catch (err) {
                setModalMessage({ show: true, title: "Lỗi Tải Game", content: err.message, type: "error" });
                setCurrentScreen('initial');
                return;
            }
        }

        if (gameData.isChunked && !gameData.knowledge) {
            setModalMessage({ show: true, title: "Đang Tải Đám Mây", content: "Đang kết nối thần thức tải các mảnh linh cốt truyện...", type: "info" });
            try {
                const chunksSnap = await getDocs(collection(db, `artifacts/${appId}/users/${userId}/games/${gameData.id}/chunks`));
                const sortedDocs = chunksSnap.docs.sort((a, b) => {
                    const idxA = parseInt(a.id.split('_')[1], 10);
                    const idxB = parseInt(b.id.split('_')[1], 10);
                    return idxA - idxB;
                });
                const combinedCompressed = sortedDocs.map(d => d.data().data).join('');
                const decompressedStr = window.LZString.decompressFromUTF16(combinedCompressed) || atob(combinedCompressed);
                const parsedFullData = JSON.parse(decompressedStr);
                finalGameData = { ...finalGameData, ...parsedFullData };
            } catch (err) {
                setModalMessage({ show: true, title: "Lỗi Tải Game", content: `Không thể tải các mảnh dữ liệu: ${err.message}`, type: "error" });
                setCurrentScreen('initial');
                return;
            }
        }

        if (gameData.isLocalPointer && !gameData.knowledge) {
            setModalMessage({ show: true, title: "Đang Trích Xuất", content: "Đang nạp dữ liệu gốc từ bộ nhớ trình duyệt...", type: "info" });
            const realData = await getAvatarFromIndexedDB(gameData.id);
            
            if (!realData) {
                setModalMessage({ 
                    show: true, 
                    title: 'Mất Dữ Liệu Gốc', 
                    content: 'Tệp lưu này chỉ còn tên trên máy chủ Firebase. Dữ liệu gốc (10MB) trong trình duyệt đã bị xóa hoặc bạn đang đăng nhập trên thiết bị/trình duyệt khác!', 
                    type: 'error' 
                });
                setCurrentScreen('initial');
                return;
            }
            finalGameData = { ...finalGameData, ...realData };
        }

        const gameIdToSet = finalGameData.id;
        let activeGameData = finalGameData;

        // Xử lý nén dữ liệu cũ nếu còn (Fallback cho tương thích ngược)
        if (!activeGameData.knowledge && finalGameData.isCompressed && window.LZString) {
            const decompressedStr = window.LZString.decompressFromUTF16(finalGameData.compressedData);
            activeGameData = JSON.parse(decompressedStr);
        }

        if (activeGameData.knowledge && activeGameData.knowledge.characters && Array.isArray(activeGameData.knowledge.characters)) {
            const cleanId = gameIdToSet.replace(/^(autosave_|manual_\d+_|manual_local_)/, '');
            
            await Promise.all(activeGameData.knowledge.characters.map(async (char) => {
                if (!char || char.isPermanentlyDead) return;
                
                const isPl = char.isPlayer || char.id === 'player' || char.id === 'player_fallback';
                const charIdForRestore = isPl ? 'player' : char.id;

                if (char.avatarBase64) {
                    await storeAvatarInIndexedDB(charIdForRestore, char.avatarBase64);
                    char.avatarStoredLocally = true;
                    if (isPl) {
                        await storeAvatarInIndexedDB(`${cleanId}_player`, char.avatarBase64);
                    }
                }

                if (char.images && (char.images.base || char.images.idle || char.images.attack_normal || Object.keys(char.images.skills || {}).length > 0)) {
                    await storeAvatarInIndexedDB(`${cleanId}_${charIdForRestore}_images`, char.images);
                }
            }));

            activeGameData.knowledge.characters.forEach(char => {
                if (!char) return;
                
                // MIGRATION: Chuyển đổi skills cũ của NPC sang equippedSkills
                if (char.skills && char.skills.length > 0) {
                    if (!char.equippedSkills) {
                        char.equippedSkills = { combat_basic_1: null, combat_basic_2: null, combat_ultimate: null, adventure_1: null, adventure_2: null, adventure_3: null };
                    }
                    if (!char.learnedSkills) char.learnedSkills = [];
                    
                    char.skills.forEach(s => {
                        if (!s) return;
                        if (s.skillCategory === 'ultimate') {
                            if (!char.equippedSkills.combat_ultimate) char.equippedSkills.combat_ultimate = s;
                            else char.learnedSkills.push(s);
                        } else {
                            if (!char.equippedSkills.combat_basic_1) char.equippedSkills.combat_basic_1 = s;
                            else if (!char.equippedSkills.combat_basic_2) char.equippedSkills.combat_basic_2 = s;
                            else char.learnedSkills.push(s);
                        }
                    });
                }
                delete char.skills; // Xóa vĩnh viễn mầm mống cũ

                if (char.inventory && !Array.isArray(char.inventory)) {
                    char.inventory = Object.values(char.inventory);
                } else if (!char.inventory) {
                    char.inventory = [];
                }
                
                const fixEvolvingStuck = (s) => { if (s && s.isEvolving) delete s.isEvolving; };
                if (char.equippedSkills) Object.values(char.equippedSkills).forEach(fixEvolvingStuck);
                if (char.learnedSkills) char.learnedSkills.forEach(fixEvolvingStuck);

                const arrayKeys = ['learnedSkills', 'longTermStatuses', 'combatStatuses'];
                arrayKeys.forEach(key => {
                    if (char[key] && !Array.isArray(char[key])) {
                        char[key] = Object.values(char[key]);
                    } else if (!char[key]) {
                        char[key] = [];
                    }
                });
            });
        }

        const normalizeNameProperty = (obj) => {
            if (!obj) return obj;
            const nameValue = obj.Name || obj.name || obj.title;
            if (nameValue) {
                delete obj.name;
                delete obj.title;
                obj.Name = nameValue;
            }
            return obj;
        };

        if (activeGameData.knowledge?.characters) activeGameData.knowledge.characters = activeGameData.knowledge.characters.map(normalizeNameProperty);
        if (activeGameData.knowledge?.locations) activeGameData.knowledge.locations = activeGameData.knowledge.locations.map(normalizeNameProperty);
        if (activeGameData.knowledge?.items) activeGameData.knowledge.items = activeGameData.knowledge.items.map(normalizeNameProperty);

        const loadedSettings = { ...INITIAL_GAME_SETTINGS, ...(activeGameData.gameSettings || activeGameData.settings || {}) };
        const loadedPlayer = activeGameData.knowledge?.characters?.find(c => c.isPlayer || c.id === 'player' || c.id === 'player_fallback') || activeGameData.knowledge?.characters?.[0] || {};
        const mergedPlayer = {
            ...INITIAL_STATS,
            ...loadedPlayer,
            id: 'player',
            isPlayer: true,
            Name: loadedPlayer.Name || loadedPlayer.name || loadedSettings.characterName || "Lê Khánh",
            learnedSkills: loadedPlayer.learnedSkills || [],
            equippedSkills: loadedPlayer.equippedSkills || INITIAL_STATS.equippedSkills,
            skills: loadedPlayer.skills || []
        };

        const baseTemplate = {
            time: { year: 0, month: 1, day: 1, hour: 8 },
            weather: "Trời trong",
            narrativeCombatState: { isActive: false, combatants: [] },
            loreLocations: [],
            loreNpcs: [],
            loreItems: [],
            locations: [],
            items: [],
            worldItems: [],
            relationships: [],
            quests: [],
            trackedQuestId: null,
            realmProgressionList: [],
            knownRecipes: [],
            eventHistory: [],
            unlearnedSkillScrolls: [],
            pendingItemsToCreate: [],
            pendingSkillCreations: [],
            characters: [],
            sharedCooldowns: { tactical: 0, potion: 0 },
            adventureSkillCooldowns: {},
            requestNpcDesign: null,
            progression: { recentMeaningfulActions: [] }
        };

        const finalKnowledge = {
            ...baseTemplate,
            ...(activeGameData.knowledge || {}),
            time: activeGameData.knowledge?.time || { year: 0, month: 1, day: 1, hour: 8 },
            weather: activeGameData.knowledge?.weather || "Trời trong"
        };

        if (!finalKnowledge.realmProgressionList || finalKnowledge.realmProgressionList.length === 0) {
            finalKnowledge.realmProgressionList = [
                "Giai Đoạn 1", "Giai Đoạn 2", "Giai Đoạn 3", "Giai Đoạn 4", "Giai Đoạn 5",
                "Giai Đoạn 6", "Giai Đoạn 7", "Giai Đoạn 8", "Giai Đoạn 9", "Giai Đoạn 10"
            ];
        }

        if (finalKnowledge.characters && Array.isArray(finalKnowledge.characters)) {
            let playerFound = false;
            finalKnowledge.characters = finalKnowledge.characters.filter(c => {
                if (c.isPlayer || c.id === 'player' || c.id === 'player_fallback') {
                    if (!playerFound) {
                        playerFound = true;
                        return true;
                    }
                    return false;
                }
                if (!c.id && !c.isCompanion && !c.Name && (c.level || c.exp)) {
                    return false;
                }
                if (c.id === 'player_fallback' || (!c.id && !c.isCompanion && c.level === 1 && c.exp === 0)) {
                    return false;
                }
                return true;
            });
        }

        const playerIndex = finalKnowledge.characters.findIndex(c => c.isPlayer || c.id === 'player' || c.id === 'player_fallback');
        if (playerIndex > -1) {
            finalKnowledge.characters[playerIndex] = mergedPlayer;
        } else {
            finalKnowledge.characters.unshift(mergedPlayer);
        }

        const systemAssistantChar = finalKnowledge.characters.find(c => c.id === 'system_assistant');
        if (systemAssistantChar) {
            if (finalKnowledge.htab) {
                finalKnowledge.htab.avatarBase64 = systemAssistantChar.avatarBase64 || systemAssistantChar.images?.idle || null;
            }
            if (finalKnowledge.systemAssistant) {
                finalKnowledge.systemAssistant.images = {
                    base: systemAssistantChar.images?.base || null,
                    idle: systemAssistantChar.images?.idle || null,
                    smile: systemAssistantChar.images?.smile || null,
                    sad: systemAssistantChar.images?.sad || null,
                    angry: systemAssistantChar.images?.angry || null,
                    laugh: systemAssistantChar.images?.laugh || null
                };
            }
        }

        const rawStoryHistory = activeGameData.storyHistory || [];
        
        const migratedStoryHistory = rawStoryHistory.map(item => {
            if (!item) return null;
            
            if (item.transient && (item.type === 'story' || item.type === 'user_choice' || item.type === 'user_custom_action')) {
                delete item.transient;
            }
            
            if (item.id === 'consolidated_placeholder') return null;

            if (item.type === 'story' && typeof item.content === 'string') return { ...item, content: parseStoryWithDialogue(item.content) };
            if (item && item.type === 'story' && typeof item.content === 'object' && item.content !== null && !Array.isArray(item.content)) return { ...item, content: [item.content] };
            return item;
        }).filter(Boolean);
        
        const alignedStoryHistory = migratedStoryHistory;
        
        let gameIdToSetFromData = gameIdToSet || crypto.randomUUID();
        gameIdToSetFromData = gameIdToSetFromData.replace(/^(autosave_|manual_\d+_\d*_?|manual_local_)/, '');

        if (gameIdToSetFromData) {
            const cachedAvatar = await getAvatarFromIndexedDB(`${gameIdToSetFromData}_player`);
            if (cachedAvatar) {
                await storeAvatarInIndexedDB('player', cachedAvatar);
            }

            if (finalKnowledge.characters) {
                for (const char of finalKnowledge.characters) {
                    const cachedImages = await getAvatarFromIndexedDB(`${gameIdToSetFromData}_${char.id}_images`);
                    if (cachedImages) {
                        char.images = cachedImages;
                    }
                }
            }
        }

        const loadedSummaries = activeGameData.storySummaries || [];

        setGameSettings(loadedSettings);
        setknowledge(finalKnowledge);
        setCurrentStory(activeGameData.currentStory || "");
        setChoices(activeGameData.choices || []);
        setStoryHistory(alignedStoryHistory);
        setCurrentGameId(gameIdToSetFromData);
        setCurrentTurn(activeGameData.currentTurn || 1);
        setVisibleStoryCount(30);
        setGameMode(activeGameData.gameMode || 'EXPLORATION');
        setActiveTrade(activeGameData.activeTrade || { trader: null, playerOffer: [], npcOffer: null, offerType: 'sell', sellMultiplier: 0, buyMultiplier: 1, itemSpecificSellBonuses: {}, itemSpecificBuyBonuses: {} });
        setStorySummaries(loadedSummaries);
        setAdventureTurnCount(activeGameData.adventureTurnCount || 0);
        setIsSummarizing(false);
        setImpromptuInput('');
        setImpromptuCharInput('');
        setActiveTab(TABS.WORLD);
        setShowLoadGameModal(false);
        setCurrentScreen('gameplay');
        justLoadedRef.current = true;
        setModalMessage({ show: true, title: 'Thành Công', content: 'Tiến trình đã được khôi phục kèm hình ảnh hoàn chỉnh.', type: 'success' });
    } catch (error) {
        console.error("Lỗi khi tải dữ liệu game:", error);
        setModalMessage({ show: true, title: 'Lỗi Tải Game', content: `Không thể xử lý dữ liệu game đã lưu: ${error.message}`, type: 'error' });
        setCurrentScreen('initial');
    }
};

