const pvpRoomRef = useRef(null);
useEffect(() => {
    const handleEmergencyExit = () => {
        const room = pvpRoomRef.current;
        if (!room?.id || !pvpApp) return;

        const projectId = pvpApp.options?.projectId;
        if (!projectId) return;

        const roomId = room.id;
        const baseUrl = `https://firestore.googleapis.com/v1/projects/${projectId}/databases/(default)/documents/pvp_rooms/${roomId}`;

        if (room.isCombatStarted) {
            const patchUrl = `${baseUrl}?updateMask.fieldPaths=status&updateMask.fieldPaths=abandonedBy`;
            const body = {
                fields: {
                    status: { stringValue: 'abandoned' },
                    abandonedBy: { stringValue: room.role }
                }
            };
            fetch(patchUrl, {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(body),
                keepalive: true
            }).catch(() => {});
        } else if (room.role === 'host') {
            fetch(baseUrl, {
                method: 'DELETE',
                keepalive: true
            }).catch(() => {});
        } else {
            const patchUrl = `${baseUrl}?updateMask.fieldPaths=status&updateMask.fieldPaths=guest&updateMask.fieldPaths=guestReady`;
            const body = {
                fields: {
                    status: { stringValue: 'waiting' },
                    guest: { nullValue: null },
                    guestReady: { booleanValue: false }
                }
            };
            fetch(patchUrl, {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(body),
                keepalive: true
            }).catch(() => {});
        }
    };

    window.addEventListener('beforeunload', handleEmergencyExit);
    window.addEventListener('unload', handleEmergencyExit);

    return () => {
        window.removeEventListener('beforeunload', handleEmergencyExit);
        window.removeEventListener('unload', handleEmergencyExit);
    };
}, []);
